"""NullMask isometric SVG illustrations.

Each constant is a base64-encoded data URI usable directly in an <img> src attribute,
or via _svg_img() helper which returns a complete <img> tag.
"""
import base64 as _b64


def _svg_img(data_uri: str, width: str = "100%", style: str = "") -> str:
    """Wrap a data URI in an <img> tag for st.markdown injection."""
    return f'<img src="{data_uri}" style="width:{width};height:auto;display:block;{style}"/>'


PRIVACY_VAULT = "data:image/svg+xml;base64,"

PRIVACY_ROUTER = "data:image/svg+xml;base64,"

PRIVACY_SHIELD = "data:image/svg+xml;base64,"

ZERO_NODE = "data:image/svg+xml;base64,"

